import 'package:flutter/material.dart';import 'piyi_avatar.dart';
class PiyiAppBar extends StatelessWidget implements PreferredSizeWidget{const PiyiAppBar({super.key,required this.title,this.subtitle,this.avatarUrl,this.actions=const[]});final String title;final String? subtitle;final String? avatarUrl;final List<Widget> actions;@override Widget build(BuildContext context)=>AppBar(title:Row(children:[PiyiAvatar(imageUrl:avatarUrl,name:title,size:38,icon:Icons.person),const SizedBox(width:12),Expanded(child:Column(crossAxisAlignment:CrossAxisAlignment.start,children:[Text(title,style:const TextStyle(fontWeight:FontWeight.w900)),if(subtitle!=null)Text(subtitle!,style:Theme.of(context).textTheme.bodySmall)]))]),actions:actions);@override Size get preferredSize=>const Size.fromHeight(kToolbarHeight);}
